// Ensures src/app/generated/open-app-bootstrap.generated.ts exists before the build.
//
// app.module.ts statically imports this file so an installed Open App's client
// packages are pulled into the bundle (their `@RegisterClass` decorators run). The
// file is git-ignored and (re)generated by `mj app install` / `mj app remove`; on a
// fresh checkout — or when no app is installed — it doesn't exist, which would break
// the build. This writes an empty, valid stub if it's missing. `mj app install`
// overwrites it with the real per-app side-effect imports.
//
// Mirrors the class-registrations-manifest lifecycle (git-ignored, ensured at prebuild).
import { existsSync, mkdirSync, writeFileSync } from 'node:fs';
import { dirname } from 'node:path';

const target = './src/app/generated/open-app-bootstrap.generated.ts';

if (!existsSync(target)) {
  mkdirSync(dirname(target), { recursive: true });
  writeFileSync(
    target,
    '// Open App bootstrap — regenerated by `mj app install` / `mj app remove`.\n' +
      '// No Open Apps installed yet.\n' +
      'export {};\n',
    'utf-8',
  );
  console.log(`[ensure-open-app-bootstrap] created empty stub at ${target}`);
}
